 quả kiến thức và kỹ năng chuyên ngành tiếng Trung thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "plo5_1774373375156_pkxejx", "code": "PLO5", "bloom_level": 3, "description": "Thể hiện kỹ năng nhận thức liên quan đến tư duy phản biện, phân tích, tổng hợp vào công việc."}, {"id": "plo6_1774373375156_yjhog8", "code": "PLO6", "bloom_level": 3, "description": "Vận dụng kỹ năng giao tiếp và công nghệ thông tin cần thiết để thực hiện các nhiệm vụ phức tạp trong môi trường làm việc liên ngành, đa văn hóa, đa quốc gia."}, {"id": "plo7_1774373375156_pre6si", "code": "PLO7", "bloom_level": 3, "description": "Làm việc độc lập và làm việc theo nhóm trong điều kiện làm việc thay đổi; nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "degree": "Đại học", "courses": [], "syllabi": [], "plan_rows": [], "po_plo_map": [], "assessments": [], "program_code": "22222", "program_name": "TRÌNH ĐỘ ĐẠI HỌC", "version_name": "Phiên bản Import", "academic_year": "2025-2026", "course_pi_map": [], "total_credits": "", "course_plo_map": [], "import_metadata": {"table_count": 14, "paragraph_count": 48}}	[{"msg": "Thiếu tổng tín chỉ.", "type": "error"}, {"msg": "Mã CTĐT \\"22222\\" đã tồn tại trong hệ thống (TRÌNH ĐỘ ĐẠI HỌC).", "type": "error"}, {"msg": "Tên phiên bản \\"Phiên bản Import\\" đã tồn tại cho CTĐT có mã \\"22222\\".", "type": "error"}]	2026-03-24 17:29:35.157815+00
