18	1	processing	{"pis": [], "pos": [{"id": "po1_1774373954336_u6a825", "code": "Mục tiêu (PO)", "description": "Mục tiêu (PO)"}, {"id": "po2_1774373954336_eynkev", "code": "PO1", "description": "Ứng dụng kiến thức: Vận dụng kiến thức về văn hóa, xã hội, chính trị, luật pháp, ngôn ngữ, và công nghệ thông tin vào thực tiễn công việc và cuộc sống. Có khả năng tự nghiên cứu, cập nhật kiến thức mới."}, {"id": "po3_1774373954336_j1f2qq", "code": "PO2", "description": "Năng lực tiếng Trung: Sử dụng thành thạo 4 kỹ năng Nghe, Nói, Đọc, Viết tiếng Trung ở trình độ cao."}, {"id": "po4_1774373954336_kphytd", "code": "PO3", "description": "Kỹ năng chuyên ngành: Vận dụng kiến thức và kỹ năng chuyên ngành (biên phiên dịch/ thương mại/ phương pháp giảng dạy/ Khoá luận tốt nghiệp) để giải quyết các vấn đề thực tiễn trong công việc."}, {"id": "po5_1774373954336_z9d01p", "code": "PO4", "description": "Kỹ năng mềm và thái độ: Làm việc độc lập, làm việc nhóm, giao tiếp hiệu quả, có trách nhiệm, sáng tạo, chủ động thích nghi với môi trường làm việc, tuân thủ chuẩn mực đạo đức nghề nghiệp."}], "plos": [{"id": "plo1_1774373954337_ucvt13", "code": "PLO1", "bloom_level": 3, "description": "Vận dụng kiến thức cơ bản về chính trị và pháp luật, khoa học xã hội và nhân văn phù hợp với chuyên ngành Ngôn ngữ Trung Quốc để đóng góp tích cực vào sự phát triển bền vững của xã hội, cộng đồng."}, {"id": "plo2_1774373954337_13ii4a", "code": "PLO2", "bloom_level": 3, "description": "Phân biệt chức năng của các thành phần cấu thành nên ngôn ngữ Trung Quốc; sử dụng thành thạo 4 kỹ năng tiếng Trung."}, {"id": "plo3_1774373954337_3852bk", "code": "PLO3", "bloom_level": 3, "description": "Sử dụng ngoại ngữ 2 tiếng Anh để nâng cao cơ hội việc làm và hiểu biết thêm về các nền văn hóa khác."}, {"id": "plo4_1774373954337_y5m9y2", "code": "PLO4", "bloom_level": 3, "description": "Áp dụng thành thạo tiếng Trung vào công việc, nhận biết chữ Hán phồn thể và thành thạo chữ Hán giản thể trong công việc; sử dụng có hiệu quả kiến thức và kỹ năng chuyên ngành tiếng Trung thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "plo5_1774373954337_wd2ymv", "code": "PLO5", "bloom_level": 3, "description": "Thể hiện kỹ năng nhận thức liên quan đến tư duy phản biện, phân tích, tổng hợp vào công việc."}, {"id": "plo6_1774373954337_9mt5ek", "code": "PLO6", "bloom_level": 3, "description": "Vận dụng kỹ năng giao tiếp và công nghệ thông tin cần thiết để thực hiện các nhiệm vụ phức tạp trong môi trường làm việc liên ngành, đa văn hóa, đa quốc gia."}, {"id": "plo7_1774373954337_f70gcf", "code": "PLO7", "bloom_level": 3, "description": "Làm việc độc lập và làm việc theo nhóm trong điều kiện làm việc thay đổi; nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "degree": "Đại học", "courses": [], "syllabi": [], "plan_rows": [], "po_plo_map": [], "assessments": [], "program_code": "", "program_name": "TRÌNH ĐỘ ĐẠI HỌC", "version_name": "Phiên bản Import", "academic_year": "", "course_pi_map": [], "total_credits": "", "course_plo_map": [], "import_metadata": {"table_count": 14, "paragraph_count": 48}}	\N	2026-03-24 17:39:14.33833+00
