 "course65_1774425418963_uy833p", "course67_1774425418963_q1itdu", "course51_1774425418963_i420rk", "course68_1774425418963_saao28", "course54_1774425418963_kxfthc", "course55_1774425418963_2l646l", "course56_1774425418963_ep8fkz", "course57_1774425418963_wtjlm1", "course58_1774425418963_jvkwzt", "course59_1774425418963_bq7j75", "course60_1774425418963_kuqi8b", "course61_1774425418963_l7dcay", "course62_1774425418963_4jet38", "course63_1774425418963_vuszl0", "course64_1774425418963_7h7ows", "course7_1774425418962_k182xc", "course8_1774425418962_3yc0ek", "course15_1774425418962_apdgb3", "course16_1774425418962_9w6yka"], "description": "Nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "pos": [{"id": "po1_1774425418960_atfpk8", "code": "PO1", "description": "Ứng dụng kiến thức: Vận dụng kiến thức về văn hóa, xã hội, chính trị, luật pháp, ngôn ngữ, và công nghệ thông tin vào thực tiễn công việc và cuộc sống. Có khả năng tự nghiên cứu, cập nhật kiến thức mới."}, {"id": "po2_1774425418960_183b0r", "code": "PO2", "description": "Năng lực tiếng Trung: Sử dụng thành thạo 4 kỹ năng Nghe, Nói, Đọc, Viết tiếng Trung ở trình độ cao."}, {"id": "po3_1774425418960_mhbye8", "code": "PO3", "description": "Kỹ năng chuyên ngành: Vận dụng kiến thức và kỹ năng chuyên ngành (biên phiên dịch/ thương mại/ phương pháp giảng dạy/ Khoá luận tốt nghiệp) để giải quyết các vấn đề thực tiễn trong công việc."}, {"id": "po4_1774425418960_bvdov6", "code": "PO4", "description": "Kỹ năng mềm và thái độ: Làm việc độc lập, làm việc nhóm, giao tiếp hiệu quả, có trách nhiệm, sáng tạo, chủ động thích nghi với môi trường làm việc, tuân thủ chuẩn mực đạo đức nghề nghiệp."}], "plos": [{"id": "plo1_1774425418959_lrkid5", "code": "PLO1", "bloom_level": 3, "description": "Vận dụng kiến thức cơ bản về chính trị và pháp luật, khoa học xã hội và nhân văn phù hợp với chuyên ngành Ngôn ngữ Trung Quốc để đóng góp tích cực vào sự phát triển bền vững của xã hội, cộng đồng ."}, {"id": "plo2_1774425418959_jh3a2q", "code": "PLO2", "bloom_level": 5, "description": "Phân biệt chức năng của các thành phần cấu thành nên ngôn ngữ Trung Quốc đồng thời sử dụng thành thạo 4 kỹ năng tiếng Trung ."}, {"id": "plo3_1774425418959_us8iaq", "code": "PLO3", "bloom_level": 3, "description": "Sử dụng ngoại ngữ 2 tiếng Anh trong các tình huống quen thuộc để nâng cao cơ hội việc làm và hiểu biết thêm về các nền văn hóa khác."}, {"id": "plo4_1774425418959_rjhn7c", "code": "PLO4", "bloom_level": 5, "description": "Áp dụng thành thạo tiếng Trung vào công việc, nhận biết chữ Hán phồn thể và thành thạo chữ Hán giản thể trong công việc; sử dụng có hiệu quả kiến thức và kỹ năng chuyên ngành tiếng Trung thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "plo5_1774425418959_3dspu3", "code": "PLO5", "bloom_level": 5, "description": "Thể hiện kỹ năng nhận thức liên quan đến tư duy phản biện, phân tích, tổng hợp vào công việc."}, {"id": "plo6_1774425418959_d0j0ke", "code": "PLO6", "bloom_level": 3, "description": "Vận dụng kỹ năng giao tiếp và công nghệ thông tin cần thiết để thực hiện các nhiệm vụ phức tạp trong môi trường làm việc liên ngành, đa văn hóa, đa quốc gia."}, {"id": "plo7_1774425418959_maqpre", "code": "PLO7", "bloom_level": 4, "description": "Làm việc độc lập và làm việc theo nhóm trong điều kiện làm việc thay đổi; nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "degree": "Đại học", "courses": [{"id": "course1_1774425418962_iaqerj", "credits": 3, "semester": 1, "course_id": null, "dept_code": "", "dept_name": "K.TA", "course_code": "ENC120", "course_name": "Anh ngữ 1", "course_type": "required"}, {"id": "course2_1774425418962_4hg7np", "credits": 3, "semester": 1, "course_id": null, "dept_code": "", "dept_name": "K.TQH", "course_code": "CHN107", "course_name": "Tiếng Trung – Nghe 1", "course_type": "requi