43	1	processing	{"pis": [{"id": "pi1_1774419270343_1479u9", "plo_id": "plo1_1774419270336_ia2v9l", "pi_code": "PI1.01", "course_ids": [], "description": "Nhận biết các vấn đề cần giải quyết về chính trị và pháp luật, khoa học xã hội và nhân văn phù hợp với chuyên ngành Ngôn ngữ Trung Quốc."}, {"id": "pi2_1774419270343_e8zx7p", "plo_id": "plo1_1774419270336_ia2v9l", "pi_code": "PI1.02", "course_ids": [], "description": "Xây dựng phương án để giải quyết các vấn đề về chính trị và pháp luật, khoa học xã hội và nhân văn phù hợp với chuyên ngành Ngôn ngữ Trung Quốc."}, {"id": "pi3_1774419270343_rpa5hh", "plo_id": "plo1_1774419270336_ia2v9l", "pi_code": "PI1.03", "course_ids": [], "description": "Kết hợp các kiến thức cơ bản, kiến thức chuyên ngành để đóng góp hữu hiệu vào sự phát triển bền vững của xã hội, cộng đồng."}, {"id": "pi4_1774419270343_fkxwi8", "plo_id": "plo2_1774419270336_3ux9de", "pi_code": "PI2.01", "course_ids": [], "description": "Nhận biết các thành phần cấu tạo nên ngôn ngữ Trung Quốc."}, {"id": "pi5_1774419270343_e1vs7y", "plo_id": "plo2_1774419270336_3ux9de", "pi_code": "PI2.02", "course_ids": [], "description": "Phân biệt chức năng của các thành phần cấu thành nên ngôn ngữ Trung Quốc."}, {"id": "pi6_1774419270343_xynqsk", "plo_id": "plo2_1774419270336_3ux9de", "pi_code": "PI2.03", "course_ids": [], "description": "Sử dụng thành thạo 4 kỹ năng tiếng Trung tương đương bậc 5 theo Khung năng lực ngoại ngữ Việt Nam."}, {"id": "pi7_1774419270343_poz136", "plo_id": "plo3_1774419270336_2kevl8", "pi_code": "PI3.01", "course_ids": [], "description": "Sử dụng ngoại ngữ 2 tiếng Anh để nâng cao cơ hội việc làm và hiểu biết thêm về các nền văn hóa khác."}, {"id": "pi8_1774419270343_jbvaj6", "plo_id": "plo4_1774419270336_pox2xh", "pi_code": "PI4.01", "course_ids": [], "description": "Áp dụng thành thạo tiếng Trung vào công việc."}, {"id": "pi9_1774419270343_sye7vy", "plo_id": "plo4_1774419270336_pox2xh", "pi_code": "PI4.02", "course_ids": [], "description": "Nhận biết chữ Hán phồn thể và thành thạo chữ Hán giản thể trong công việc."}, {"id": "pi10_1774419270343_nzy0fs", "plo_id": "plo4_1774419270336_pox2xh", "pi_code": "PI4.03", "course_ids": [], "description": "Khai thác thông tin và cập nhật kiến thức chuyên ngành thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "pi11_1774419270343_09987k", "plo_id": "plo5_1774419270336_cbjz5a", "pi_code": "PI5.01", "course_ids": [], "description": "Phân tích thông tin, đưa ra luận điểm có căn cứ."}, {"id": "pi12_1774419270343_lywcq0", "plo_id": "plo5_1774419270336_cbjz5a", "pi_code": "PI5.02", "course_ids": [], "description": "Hệ thống lại vấn đề, đưa ra kết luận về cách thức vận hành của vấn đề hệ thống."}, {"id": "pi13_1774419270343_f7vhfk", "plo_id": "plo5_1774419270336_cbjz5a", "pi_code": "PI5.03", "course_ids": [], "description": "Lập kế hoạch, thực hiện và đánh giá công việc chuyên môn."}, {"id": "pi14_1774419270343_n0bgub", "plo_id": "plo6_1774419270336_nmm2f7", "pi_code": "PI6.01", "course_ids": [], "description": "Sử dụng tốt các chiến lược giao tiếp bằng văn bản và bằng lời như thuyết trình, thương lượng, truyền đạt thông tin."}, {"id": "pi15_1774419270343_f15c52", "plo_id": "plo6_1774419270336_nmm2f7", "pi_code": "PI6.02", "course_ids": [], "description": "Áp dụng thành thạo kỹ năng giao tiếp ứng xử cần thiết để thực hiện các nhiệm vụ phức tạp."}, {"id": "pi16_1774419270343_y1wse7", "plo_id": "plo6_1774419270336_nmm2f7", "pi_code": "PI6.03", "course_ids": [], "description": "Sử dụng Word, Excel, Powerpoint ….soạn thảo, trình bày các loại văn bản trong học tập, nghiên cứu và công việc có hiệu quả."}, {"id": "pi17_1774419270343_nvnt89", "plo_id": "plo6_1774419270336_nmm2f7", "pi_code": "PI6.04", "course_ids": [], "description": "Sử dụng có hiệu quả các phần mềm chuyên dụng để phục vụ học tập và công việc chuyên môn liên quan đến tiếng Trung."}, {"id": "pi18_1774419270343_k9qbfe", "plo_id": "plo7_1774419270336_4vb587", "pi_code": "PI7.01", "course_ids": [], "description": "Đưa ra các nhận định cá nhân trong điều kiện làm việc thay đổi"}, {"id": "pi19_1774419270343_yn3i2v", "plo_id": "plo7_1774419270336_4vb587", "pi_code": "PI7.02", "course_ids": [], "description": "Xác định được đầy đủ mục tiêu của nhóm, vai trò, trách nhiệm của các thành viên"}, {"id": "pi20_1774419270343_h2l5l1", "plo_id": "plo7_1774419270336_4vb587", "pi_code": "PI7.03", "course_ids": [], "description": "Tham gia hoạch định, lên chương trình và phối hợp trong thực hiện hoạt động nhóm đạt được mục tiêu đã đề ra."}, {"id": "pi21_1774419270343_5s83ap", "plo_id": "plo7_1774419270336_4vb587", "pi_code": "PI7.04", "course_ids": [], "description": "Nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "pos": [{"id": "po1_1774419270337_nfwq00", "code": "PO1", "description": "Ứng dụng kiến thức: Vận dụng kiến thức về văn hóa, xã hội, chính trị, luật pháp, ngôn ngữ, và công nghệ thông tin vào thực tiễn công việc và cuộc sống. Có khả năng tự nghiên cứu, cập nhật kiến thức mới."}, {"id": "po2_1774419270337_vj71fb", "code": "PO2", "description": "Năng lực tiếng Trung: Sử dụng thành thạo 4 kỹ năng Nghe, Nói, Đọc, Viết tiếng Trung ở trình độ cao."}, {"id": "po3_1774419270337_jqruil", "code": "PO3", "description": "Kỹ năng chuyên ngành: Vận dụng kiến thức và kỹ năng chuyên ngành (biên phiên dịch/ thương mại/ phương pháp giảng dạy/ Khoá luận tốt nghiệp) để giải quyết các vấn đề thực tiễn trong công việc."}, {"id": "po4_1774419270337_7sh1na", "code": "PO4", "description": "Kỹ năng mềm và thái độ: Làm việc độc lập, làm việc nhóm, giao tiếp hiệu quả, có trách nhiệm, sáng tạo, chủ động thích nghi với môi trường làm việc, tuân thủ chuẩn mực đạo đức nghề nghiệp."}], "plos": [{"id": "plo1_1774419270336_ia2v9l", "code": "PLO1", "bloom_level": 3, "description": "dụng kiến thức cơ bản về chính trị và pháp luật, khoa học xã hội và nhân văn phù hợp với chuyên ngành Ngôn ngữ Trung Quốc để đóng góp tích cực vào sự phát triển bền vững của xã hội, cộng đồng ."}, {"id": "plo2_1774419270336_3ux9de", "code": "PLO2", "bloom_level": 5, "description": "Phân biệt chức năng của các thành phần cấu thành nên ngôn ngữ Trung Quốc đồng thời sử dụng thành thạo 4 kỹ năng tiếng Trung ."}, {"id": "plo3_1774419270336_2kevl8", "code": "PLO3", "bloom_level": 3, "description": "Sử dụng ngoại ngữ 2 tiếng Anh trong các tình huống quen thuộc để nâng cao cơ hội việc làm và hiểu biết thêm về các nền văn hóa khác."}, {"id": "plo4_1774419270336_pox2xh", "code": "PLO4", "bloom_level": 5, "description": "Áp dụng thành thạo tiếng Trung vào công việc, nhận biết chữ Hán phồn thể và thành thạo chữ Hán giản thể trong công việc; sử dụng có hiệu quả kiến thức và kỹ năng chuyên ngành tiếng Trung thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "plo5_1774419270336_cbjz5a", "code": "PLO5", "bloom_level": 5, "description": "Thể hiện kỹ năng nhận thức liên quan đến tư duy phản biện, phân tích, tổng hợp vào công việc."}, {"id": "plo6_1774419270336_nmm2f7", "code": "PLO6", "bloom_level": 3, "description": "Vận dụng kỹ năng giao tiếp và công nghệ thông tin cần thiết để thực hiện các nhiệm vụ phức tạp trong môi trường làm việc liên ngành, đa văn hóa, đa quốc gia."}, {"id": "plo7_1774419270336_4vb587", "code": "PLO7", "bloom_level": 4, "description": "Làm việc độc lập và làm việc theo nhóm trong điều kiện làm việc thay đổi; nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "degree": "Đại học", "courses": [{"id": "course1_1774419270340_gcune1", "credits": 3, "semester": 1, "course_id": null, "dept_code": "", "dept_name": "K.TA", "course_code": "ENC120", "course_name": "Anh ngữ 1", "course_type": "required"}, {"id": "course2_1774419270340_lso85g", "credits": 3, "semester": 1, "course_id": null, "dept_code": "", "dept_name": "K.TQH", "course_