5iri90", "plo_id": "plo5_1774421542765_92uc71", "pi_code": "PI5.03", "course_ids": [], "description": "Lập kế hoạch, thực hiện và đánh giá công việc chuyên môn."}, {"id": "pi14_1774421542772_2opekk", "plo_id": "plo6_1774421542765_owpfjr", "pi_code": "PI6.01", "course_ids": [], "description": "Sử dụng tốt các chiến lược giao tiếp bằng văn bản và bằng lời như thuyết trình, thương lượng, truyền đạt thông tin."}, {"id": "pi15_1774421542772_891uf4", "plo_id": "plo6_1774421542765_owpfjr", "pi_code": "PI6.02", "course_ids": [], "description": "Áp dụng thành thạo kỹ năng giao tiếp ứng xử cần thiết để thực hiện các nhiệm vụ phức tạp."}, {"id": "pi16_1774421542772_uxb6ch", "plo_id": "plo6_1774421542765_owpfjr", "pi_code": "PI6.03", "course_ids": [], "description": "Sử dụng Word, Excel, Powerpoint ….soạn thảo, trình bày các loại văn bản trong học tập, nghiên cứu và công việc có hiệu quả."}, {"id": "pi17_1774421542772_owsmc0", "plo_id": "plo6_1774421542765_owpfjr", "pi_code": "PI6.04", "course_ids": [], "description": "Sử dụng có hiệu quả các phần mềm chuyên dụng để phục vụ học tập và công việc chuyên môn liên quan đến tiếng Trung."}, {"id": "pi18_1774421542772_fpfrir", "plo_id": "plo7_1774421542765_8rjreq", "pi_code": "PI7.01", "course_ids": [], "description": "Đưa ra các nhận định cá nhân trong điều kiện làm việc thay đổi"}, {"id": "pi19_1774421542772_lxdzxc", "plo_id": "plo7_1774421542765_8rjreq", "pi_code": "PI7.02", "course_ids": [], "description": "Xác định được đầy đủ mục tiêu của nhóm, vai trò, trách nhiệm của các thành viên"}, {"id": "pi20_1774421542772_tacq7f", "plo_id": "plo7_1774421542765_8rjreq", "pi_code": "PI7.03", "course_ids": [], "description": "Tham gia hoạch định, lên chương trình và phối hợp trong thực hiện hoạt động nhóm đạt được mục tiêu đã đề ra."}, {"id": "pi21_1774421542772_dsxotf", "plo_id": "plo7_1774421542765_8rjreq", "pi_code": "PI7.04", "course_ids": [], "description": "Nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "pos": [{"id": "po2_1774421542766_1xgjms", "code": "PO2", "description": "Năng lực tiếng Trung: Sử dụng thành thạo 4 kỹ năng Nghe, Nói, Đọc, Viết tiếng Trung ở trình độ cao."}, {"id": "po3_1774421542766_us02of", "code": "PO3", "description": "Kỹ năng chuyên ngành: Vận dụng kiến thức và kỹ năng chuyên ngành (biên phiên dịch/ thương mại/ phương pháp giảng dạy/ Khoá luận tốt nghiệp) để giải quyết các vấn đề thực tiễn trong công việc."}, {"id": "po4_1774421542766_h0kyyr", "code": "PO4", "description": "Kỹ năng mềm và thái độ: Làm việc độc lập, làm việc nhóm, giao tiếp hiệu quả, có trách nhiệm, sáng tạo, chủ động thích nghi với môi trường làm việc, tuân thủ chuẩn mực đạo đức nghề nghiệp."}], "plos": [{"id": "plo2_1774421542765_p3ru9n", "code": "PLO2", "bloom_level": 5, "description": "Phân biệt chức năng của các thành phần cấu thành nên ngôn ngữ Trung Quốc đồng thời sử dụng thành thạo 4 kỹ năng tiếng Trung ."}, {"id": "plo3_1774421542765_j61qd9", "code": "PLO3", "bloom_level": 3, "description": "Sử dụng ngoại ngữ 2 tiếng Anh trong các tình huống quen thuộc để nâng cao cơ hội việc làm và hiểu biết thêm về các nền văn hóa khác."}, {"id": "plo4_1774421542765_zds9og", "code": "PLO4", "bloom_level": 5, "description": "Áp dụng thành thạo tiếng Trung vào công việc, nhận biết chữ Hán phồn thể và thành thạo chữ Hán giản thể trong công việc; sử dụng có hiệu quả kiến thức và kỹ năng chuyên ngành tiếng Trung thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "plo5_1774421542765_92uc71", "code": "PLO5", "bloom_level": 5, "description": "Thể hiện kỹ năng nhận thức liên quan đến tư duy phản biện, phân tích, tổng hợp vào công việc."}, {"id": "plo6_1774421542765_owpfjr", "code": "PLO6", "bloom_level": 3, "description": "Vận dụng kỹ năng giao tiếp và công nghệ thông tin cần thiết để thực hiện các nhiệm vụ phức tạp trong môi trường làm việc liên ngành, đa văn hóa, đa quốc gia."}, 