"course65_1774502130308_zdhjec", "course67_1774502130308_wuky92", "course51_1774502130307_ij9upt", "course68_1774502130308_inamih", "course54_1774502130307_4wxng1", "course55_1774502130307_i5ab9b", "course56_1774502130307_ztt00n", "course57_1774502130307_ev1rww", "course58_1774502130307_ujpfj7", "course59_1774502130307_urliw1", "course60_1774502130307_phks6w", "course61_1774502130307_j70rnz", "course62_1774502130307_fog9c7", "course63_1774502130308_7a207x", "course64_1774502130308_b4visb", "course7_1774502130307_pn7v3v", "course8_1774502130307_y3xq7q", "course15_1774502130307_7i8orc", "course16_1774502130307_fpz88n"], "description": "Nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "pos": [{"id": "po1_1774502130303_afw21c", "code": "PO1", "description": "Ứng dụng kiến thức: Vận dụng kiến thức về văn hóa, xã hội, chính trị, luật pháp, ngôn ngữ, và công nghệ thông tin vào thực tiễn công việc và cuộc sống. Có khả năng tự nghiên cứu, cập nhật kiến thức mới."}, {"id": "po2_1774502130303_55encl", "code": "PO2", "description": "Năng lực tiếng Trung: Sử dụng thành thạo 4 kỹ năng Nghe, Nói, Đọc, Viết tiếng Trung ở trình độ cao."}, {"id": "po3_1774502130303_mirgoc", "code": "PO3", "description": "Kỹ năng chuyên ngành: Vận dụng kiến thức và kỹ năng chuyên ngành (biên phiên dịch/ thương mại/ phương pháp giảng dạy/ Khoá luận tốt nghiệp) để giải quyết các vấn đề thực tiễn trong công việc."}, {"id": "po4_1774502130303_mlmpj9", "code": "PO4", "description": "Kỹ năng mềm và thái độ: Làm việc độc lập, làm việc nhóm, giao tiếp hiệu quả, có trách nhiệm, sáng tạo, chủ động thích nghi với môi trường làm việc, tuân thủ chuẩn mực đạo đức nghề nghiệp."}], "plos": [{"id": "plo1_1774502130301_aazo82", "code": "PLO1", "bloom_level": 3, "description": "Vận dụng kiến thức cơ bản về chính trị và pháp luật, khoa học xã hội và nhân văn phù hợp với chuyên ngành Ngôn ngữ Trung Quốc để đóng góp tích cực vào sự phát triển bền vững của xã hội, cộng đồng ."}, {"id": "plo2_1774502130301_uwfq7r", "code": "PLO2", "bloom_level": 5, "description": "Phân biệt chức năng của các thành phần cấu thành nên ngôn ngữ Trung Quốc đồng thời sử dụng thành thạo 4 kỹ năng tiếng Trung ."}, {"id": "plo3_1774502130301_mc7ky3", "code": "PLO3", "bloom_level": 3, "description": "Sử dụng ngoại ngữ 2 tiếng Anh trong các tình huống quen thuộc để nâng cao cơ hội việc làm và hiểu biết thêm về các nền văn hóa khác."}, {"id": "plo4_1774502130302_vfm1tx", "code": "PLO4", "bloom_level": 5, "description": "Áp dụng thành thạo tiếng Trung vào công việc, nhận biết chữ Hán phồn thể và thành thạo chữ Hán giản thể trong công việc; sử dụng có hiệu quả kiến thức và kỹ năng chuyên ngành tiếng Trung thuộc lĩnh vực (a) thương mại, hoặc (b) biên phiên dịch, hoặc (c) phương pháp giảng dạy, hoặc (d) khóa luận tốt nghiệp."}, {"id": "plo5_1774502130302_lowt1u", "code": "PLO5", "bloom_level": 5, "description": "Thể hiện kỹ năng nhận thức liên quan đến tư duy phản biện, phân tích, tổng hợp vào công việc."}, {"id": "plo6_1774502130302_egtcx2", "code": "PLO6", "bloom_level": 3, "description": "Vận dụng kỹ năng giao tiếp và công nghệ thông tin cần thiết để thực hiện các nhiệm vụ phức tạp trong môi trường làm việc liên ngành, đa văn hóa, đa quốc gia."}, {"id": "plo7_1774502130302_rfjprx", "code": "PLO7", "bloom_level": 4, "description": "Làm việc độc lập và làm việc theo nhóm trong điều kiện làm việc thay đổi; nhận thức và tuân thủ chuẩn mực đạo đức và trách nhiệm xã hội và nghề nghiệp trong bối cảnh toàn cầu hóa."}], "degree": "Đại học", "courses": [{"id": "course1_1774502130307_59whje", "credits": 3, "semester": 1, "course_id": null, "dept_code": "", "dept_name": "K.TA", "course_code": "ENC120", "course_name": "Anh ngữ 1", "course_type": "required"}, {"id": "course2_1774502130307_gq4nux", "credits": 3, "semester": 1, "course_id": null, "dept_code": "", "dept_name": "K.TQH", "course_code": "CHN107", "course_name": "Tiếng Trung – Nghe 1", "course_type": "requir